// // This module implements a 1-to-4 demultiplexer instead of a 4-to-1 multiplexer
module mux_4to1(
    input [1:0] a,
    input [1:0] b,
    input [1:0] c,
    input [1:0] d,
    input [1:0] sel,
    output [1:0] y
);
    assign y = (sel == 2'b00) ? a : 
               (sel == 2'b01) ? b : 
               (sel == 2'b10) ? c : d;
endmodule
